 14→const maxLimit = 100
 15→
 16→// itemColumns is the canonical SELECT column list for the items table.
 17→const itemColumns = `id, owner_id, type, status, sensitivity, title, content_text,
 18→	content_url, tags, metadata, auto_metadata, source, source_url,
 19→	created_at, updated_at, captured_at`
