 31→// GetByID returns a single item by ID and owner. Returns nil, nil if not found.
 32→func (s *Service) GetByID(ctx context.Context, ownerID, itemID uuid.UUID) (*Item, error) {
 33→	query := fmt.Sprintf(`SELECT %s FROM items WHERE owner_id = $1 AND id = $2`, itemColumns)
 34→	row := s.pool.QueryRow(ctx, query, ownerID, itemID)
 35→	it, err := scanItem(row)
 36→	if errors.Is(err, pgx.ErrNoRows) {
 37→		return nil, nil
 38→	}
 39→	if err != nil {
 40→		return nil, fmt.Errorf("item: get by id: %w", err)
 41→	}
 42→	return it, nil
 43→}
 44→
 45→// List returns a page of items matching the given filter, sorted and paginated.
 46→func (s *Service) List(ctx context.Context, ownerID uuid.UUID, filter *Filter, limit, offset int, sort *Sort) (*SearchResult, error) {
 47→	limit = clampLimit(limit, maxLimit)
 48→	offset = clampOffset(offset)
 49→
 50→	qb := &queryBuilder{}
 51→	qb.add("owner_id = $%d", ownerID)
 52→	applyFilter(qb, filter)
 53→	whereClause := qb.where()
 54→
 55→	// Count total
 56→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
 57→	var total int
 58→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
 59→		return nil, fmt.Errorf("item: list count: %w", err)
 60→	}
 61→
 62→	// Determine sort
 63→	orderCol := "created_at"
 64→	orderDir := "DESC"
 65→	if sort != nil {
 66→		if col, ok := sortFieldToColumn(sort.Field); ok {
 67→			orderCol = col
 68→		}
 69→		orderDir = sortDirectionSQL(sort.Direction)
 70→	}
 71→
 72→	dataQuery := fmt.Sprintf(`SELECT %s FROM items %s ORDER BY %s %s LIMIT $%d OFFSET $%d`,
 73→		itemColumns, whereClause, orderCol, orderDir, qb.nextParam(), qb.nextParam()+1)
 74→	qb.args = append(qb.args, limit, offset)
 75→
 76→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
 77→	if err != nil {
 78→		return nil, fmt.Errorf("item: list query: %w", err)
 79→	}
 80→	defer rows.Close()
 81→
 82→	items, err := scanItems(rows)
 83→	if err != nil {
 84→		return nil, fmt.Errorf("item: list scan: %w", err)
 85→	}
 86→
 87→	return &SearchResult{
 88→		Items:   items,
 89→		Total:   total,
 90→		HasMore: offset+len(items) < total,
 91→	}, nil
 92→}
 93→
 94→// Search performs full-text search over items using the search_vector column.
 95→func (s *Service) Search(ctx context.Context, ownerID uuid.UUID, query string, filter *Filter, limit int, threshold float64) (*SearchResult, error) {
 96→	if query == "" {
 97→		return &SearchResult{Items: []*Item{}}, nil
 98→	}
 99→	limit = clampLimit(limit, maxLimit)
100→
101→	qb := &queryBuilder{}
102→	qb.add("owner_id = $%d", ownerID)
103→	qb.add("search_vector @@ plainto_tsquery('english', $%d)", query)
104→	applyFilter(qb, filter)
105→	whereClause := qb.where()
106→
107→	// Count total matches
108→	countQuery := fmt.Sprintf("SELECT COUNT(*) FROM items %s", whereClause)
109→	var total int
110→	if err := s.pool.QueryRow(ctx, countQuery, qb.args...).Scan(&total); err != nil {
111→		return nil, fmt.Errorf("item: search count: %w", err)
112→	}
113→
114→	dataQuery := fmt.Sprintf(
115→		`SELECT %s FROM items %s ORDER BY ts_rank(search_vector, plainto_tsquery('english', $2)) DESC LIMIT $%d`,
116→		itemColumns, whereClause, qb.nextParam())
117→	qb.args = append(qb.args, limit)
118→
119→	rows, err := s.pool.Query(ctx, dataQuery, qb.args...)
120→	if err != nil {
121→		return nil, fmt.Errorf("item: search query: %w", err)
122→	}
123→	defer rows.Close()
124→
125→	items, err := scanItems(rows)
126→	if err != nil {
127→		return nil, fmt.Errorf("item: search scan: %w", err)
128→	}
129→
130→	return &SearchResult{
131→		Items:   items,
132→		Total:   total,
133→		HasMore: len(items) < total,
134→	}, nil
135→}
