 37→// PageFetchWorker fetches and extracts readable content from bookmark URLs.
 38→type PageFetchWorker struct {
 39→	river.WorkerDefaults[PageFetchArgs]
 40→	Items   ItemContentUpdater
 41→	Storage *storage.Client // nil if S3 not configured
 42→	Client  *http.Client    // nil uses a default client with timeout
